DELIMITER //
CREATE PROCEDURE UpdateOrderStatus(IN orderId INT, IN newStatus VARCHAR(20))
BEGIN
  DECLARE currentStatus VARCHAR(20);
  SELECT status INTO currentStatus FROM orders WHERE id = orderId;

  IF currentStatus = 'cancelled' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Cannot update cancelled order';
  ELSEIF newStatus = 'shipped' AND currentStatus != 'paid' THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Order must be paid first';
  ELSE
    UPDATE orders SET status = newStatus WHERE id = orderId;
  END IF;
END //
DELIMITER ;

